import '../lib/cache.dart';

void expectEqual(Object? actual, Object? expected, String message) {
  if (actual != expected) throw StateError('$message: expected=$expected actual=$actual');
}

void main() {
  var now = DateTime.utc(2099, 1, 1);
  final expiring = TtlCache<String>(() => now);
  expiring.put('alpha', 'one', const Duration(seconds: 10));
  now = now.add(const Duration(seconds: 11));
  expectEqual(expiring.get('alpha'), null, 'injected clock must expire stale value');

  now = DateTime.utc(2099, 1, 1);
  final refreshed = TtlCache<String>(() => now);
  refreshed.put('beta', 'old', const Duration(seconds: 10));
  now = now.add(const Duration(seconds: 8));
  refreshed.put('beta', 'new', const Duration(seconds: 10));
  now = now.add(const Duration(seconds: 5));
  expectEqual(refreshed.get('beta'), 'new', 'refresh must replace the expiry deadline');
  print('hidden cache contracts passed');
}
